This is my current workaround, it's really annoying to need to use the keyboard visibility plugin and re-define the text field for this

```
import 'dart:async';
import 'dart:io';

import 'package:flutter/material.dart';
import 'package:flutter_keyboard_visibility/flutter_keyboard_visibility.dart';
import 'package:ironsight_mobile/presentation/themes/brand_colors.dart';
import 'package:ironsight_mobile/presentation/themes/space.dart';

class MultilineTextFormField extends StatefulWidget {
  final TextEditingController? controller;
  final FormFieldValidator<String>? validator;
  final InputDecoration? decoration;
  final String? initialValue;
  final ValueChanged<String>? onChanged;

  const MultilineTextFormField({
    super.key,
    this.controller,
    this.validator,
    this.decoration,
    this.onChanged,
    this.initialValue,
  });

  @override
  State<MultilineTextFormField> createState() => MultilineTextFormFieldState();
}

class MultilineTextFormFieldState extends State<MultilineTextFormField> {
  StreamSubscription<bool>? keyboardSubscription;
  OverlayEntry? keyboardBar;

  @override
  void initState() {
    super.initState();
    if (Platform.isIOS) {
      keyboardSubscription = KeyboardVisibilityController()
          .onChange
          .distinct()
          .listen((keyboardIsOpen) {
        if (!keyboardIsOpen) {
          keyboardBar?.remove();
          keyboardBar = null;
        } else {
          Overlay.of(context)?.insert(buildKeyboardBar());
        }
      });
    }
  }

  @override
  void dispose() {
    keyboardSubscription?.cancel();
    keyboardBar?.remove();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return TextFormField(
      onChanged: widget.onChanged,
      initialValue: widget.initialValue,
      controller: widget.controller,
      validator: widget.validator,
      decoration: widget.decoration?.copyWith(
            alignLabelWithHint: true,
          ) ??
          const InputDecoration(alignLabelWithHint: true),
      maxLines: null,
      minLines: 4,
      scrollPadding: const EdgeInsets.all(Space.large).copyWith(
        bottom: Platform.isIOS ? 135.0 : 85.0,
      ),
    );
  }

  OverlayEntry buildKeyboardBar() {
    keyboardBar = OverlayEntry(
      builder: (context) => Positioned(
        bottom: MediaQuery.of(context).viewInsets.bottom,
        right: Space.none,
        left: Space.none,
        child: Container(
          width: double.maxFinite,
          padding: const EdgeInsets.symmetric(
            horizontal: Space.smaller,
            vertical: Space.smallest,
          ),
          decoration: const BoxDecoration(
            border: Border(top: BorderSide(color: BrandColors.greyLightest)),
            color: BrandColors.white,
          ),
          child: Align(
            alignment: Alignment.topRight,
            child: TextButton(
              onPressed: FocusScope.of(context).unfocus,
              child: const Text("Done"),
            ),
          ),
        ),
      ),
    );

    return keyboardBar!;
  }
}
```

